			&lt;td data-mce-style=&quot;width: 117.547px;&quot; style=&quot;width: 117.547px;&quot;&gt;&lt;span style=&quot;&quot;&gt;मैंडलीवियम&lt;/span&gt;&lt;/td&gt;
